external_knowledge:
- "digital sea" metaphorically refers to the cloud storage services;
- "more than a thousand stars" metaphorically represents the number of files stored being more than 1000;
- "vast expanses beyond the horizon" metaphorically represents the storage limit exceeding 10 units.

sql:
SELECT service_name
FROM cloud_storage_services
WHERE provider = 'Microsoft';

SELECT service_id, COUNT(*) AS total_file_shares
FROM file_sharing
GROUP BY service_id;

SELECT user_id, COUNT(*) AS total_collaborations
FROM collaboration
GROUP BY user_id;

SELECT * 
FROM cloud_storage_services 
WHERE service_id = 1;
